            {{ t("auth.button.signUp") }}
          </button>
          <button @click="goPage('ForgotAccount')" class="inline-flex jus-content-center ali-items-center overflow-hidden min-w-min-content min-h-32 h-32 mt-8 px-4 gap-5 fs-16 fw-500 lh-24 text-ali-center text-overflow-ellipsis text-decoration-none white-space-nowrap word-break-all text-link bg-transparent hover:text-btn focus-visible:text-yellow active:text-yellow appearance-none user-select-none">
