  </div>
</template>

<script setup lang="ts">
import { useI18n } from "vue-i18n"
import { USER_ID_RULE, PASSWORD_RULE } from "@/constants"
import { goPage } from "@/modules/utils/util"
import { ref, onMounted } from "vue"
import { AxiosError } from "axios"
import useStore from "@/stores"

const { t } = useI18n()

const store = useStore()

const userId = ref("")
const userIdError = ref("")
const userIdInput = ref<HTMLInputElement | null>(null)

const password = ref("")
const passwordError = ref("")
const showPassword = ref(false)

const loginError = ref("")

const errorCodeMap: Record<string, string> = {
  ERR_USER_NOT_FOUND: "auth.error.login.failed",
  ERR_PASSWORD_MISMATCH: "auth.error.login.failed",
  ERR_USER_BANNED: "auth.error.login.banned",
  ERR_USER_DORMANT: "auth.error.login.dormant",
  ERR_USER_SUSPENDED: "auth.error.login.suspended",
}

const validateUserId = () => {
  userIdError.value = ""

  if (!userId.value) {
    return userIdError.value = "auth.error.userId.required"
  }

  if (userId.value.length < USER_ID_RULE.MIN_LENGTH || USER_ID_RULE.MAX_LENGTH < userId.value.length) {
    return userIdError.value = "auth.error.userId.length"
  }
}

const validatePassword = () => {
  passwordError.value = ""

  if (!password.value.trim()) {
    passwordError.value = "auth.error.password.required"
  }
}

const clearUserId = () => {
  userId.value = ""
}

const clearUserIdError = () => {
  userIdError.value = ""
  loginError.value = ""
}

const clearPassword = () => {
  password.value = ""
}

const clearPasswordError = () => {
  passwordError.value = ""
  loginError.value = ""
}

const login = async () => {
  validateUserId()
  validatePassword()

  if (userIdError.value || passwordError.value) return

  const res = await store.auth.login({ userId: userId.value, password: password.value })

  if (res.success) {
    goPage("Home")
  } else {
    if (res.error instanceof AxiosError) {
      const resultCode = res.error.response?.data?.code as string
      loginError.value = errorCodeMap[resultCode] ?? "auth.error.login.failed"
    }
  }
}

onMounted(() => {
  userIdInput.value?.focus()
})
</script>

